#include "SYsULexer.h" // 确保这里的头文件名与您生成的词法分析器匹配
#include <fstream>
#include <iostream>
#include <unordered_map>
#include <sstream>
#include <regex>

// 映射定义，将ANTLR的tokenTypeName映射到clang的格式
std::unordered_map<std::string, std::string> tokenTypeMapping = {
  { "Int", "int" },
  { "Void", "void" },
  { "Return", "return" },
  { "If", "if" },
  { "Else", "else" },
  { "While", "while" },
  { "For", "for" },
  { "Break", "break" },
  { "Continue", "continue" },
  { "Identifier", "identifier" },
  { "LeftParen", "l_paren" },
  { "RightParen", "r_paren" },
  { "RightBrace", "r_brace" },
  { "LeftBrace", "l_brace" },
  { "LeftBracket", "l_square" },
  { "RightBracket", "r_square" },
  { "Constant", "numeric_constant" },
  { "Semi", "semi" },
  { "EOF", "eof" },
  { "Equal", "equal" },
  { "Plus", "plus" },
  { "Minus", "minus" },
  { "Star", "star" },
  { "Div", "slash" },
  { "Comma", "comma" },
  { "Less", "less" },
  { "Greater", "greater" },
  { "LessEqual", "less_equal" },
  { "GreaterEqual", "greater_equal" },
  { "EqualEqual", "equal_equal" },
  { "ExclaimEqual", "exclaim_equal" },
  { "Ampersand", "amp" },
  { "Pipe", "pipe" },
  { "Caret", "caret" },
  { "Tilde", "tilde" },
  { "Question", "question" },
  { "Colon", "colon" },
  { "Exclamation", "exclaim" },
  { "Percent", "percent" },
  { "AmpersandAmpersand", "ampamp" },
  { "PipePipe", "pipepipe" },
  { "PlusPlus", "plusplus" },
  { "MinusMinus", "minusminus" },
  { "LeftShift", "lessless" },
  { "RightShift", "greatergreater" },
};

// Global state for tracking file name and line tracking
std::string currentFileName = "";
int currentLine = 1;
int lastTokenEndLine = 1;
int lastTokenEndColumn = 0;

// Map from line number to file name (from #line markers)
std::unordered_map<int, std::string> lineToFileMap;

void
parseLineMarkers(const std::string& inputFile)
{
  // Read the file and parse #line markers
  std::ifstream file(inputFile);
  if (!file) return;

  std::string line;
  int lineNum = 1;
  std::regex lineRegex(R"(#\s*(\d+)\s+\"([^\"]+)\")");
  std::smatch match;

  while (std::getline(file, line)) {
    if (line.size() > 0 && line[0] == '#') {
      if (std::regex_search(line, match, lineRegex)) {
        int markerLine = std::stoi(match[1]);
        std::string fileName = match[2];
        lineToFileMap[markerLine] = fileName;
      }
    }
    lineNum++;
  }
}

std::string
getFileForLine(int line)
{
  // Find the most recent file mapping for this line
  std::string result = "";
  for (auto& pair : lineToFileMap) {
    if (pair.first <= line) {
      result = pair.second;
    } else {
      break;
    }
  }
  return result.empty() ? currentFileName : result;
}

void
print_token(const antlr4::Token* token,
            const antlr4::CommonTokenStream& tokens,
            std::ofstream& outFile,
            const antlr4::Lexer& lexer)
{
  auto& vocabulary = lexer.getVocabulary();

  auto tokenTypeName =
    std::string(vocabulary.getSymbolicName(token->getType()));

  if (tokenTypeName.empty())
    tokenTypeName = "<UNKNOWN>"; // 处理可能的空字符串情况

  if (tokenTypeMapping.find(tokenTypeName) != tokenTypeMapping.end()) {
    tokenTypeName = tokenTypeMapping[tokenTypeName];
  }

  // Get token position
  int tokenLine = token->getLine();
  int tokenColumn = token->getCharPositionInLine() + 1;

  // Get the file name for this token's line
  std::string tokenFileName = getFileForLine(tokenLine);

  // Check for StartOfLine and LeadingSpace
  bool startOfLine = false;
  bool leadingSpace = false;

  // Check if this is the first token on the line
  // by comparing with the previous token's line
  if (tokenLine != lastTokenEndLine) {
    // New line - this is the first token on this line
    startOfLine = true;
  }

  // Check for leading space
  if (tokenLine > lastTokenEndLine) {
    // New line - there's likely leading space (whitespace before first token)
    leadingSpace = true;
  } else if (tokenLine == lastTokenEndLine) {
    // Same line as previous token
    if (lastTokenEndColumn < tokenColumn - 1) {
      // There's space between previous token end and this token
      leadingSpace = true;
    }
  }

  // First token is always at start of line
  if (lastTokenEndColumn == 0 && lastTokenEndLine == 1) {
    startOfLine = true;
  }

  // Update last token position
  std::string tokenText = token->getText();
  if (tokenText != "<EOF>") {
    lastTokenEndLine = tokenLine;
    lastTokenEndColumn = tokenColumn + tokenText.length();
  }

  // Build location info
  std::string locInfo = " Loc=<" + tokenFileName + ":" + 
                        std::to_string(tokenLine) + ":" + 
                        std::to_string(tokenColumn) + ">";

  if (token->getText() != "<EOF>")
    outFile << tokenTypeName << " '" << token->getText() << "'";
  else
    outFile << tokenTypeName << " '"
            << "'";
  if (startOfLine)
    outFile << "\t [StartOfLine]";
  if (leadingSpace)
    outFile << " [LeadingSpace]";
  outFile << locInfo << std::endl;
}

int
main(int argc, char* argv[])
{
  if (argc != 3) {
    std::cout << "Usage: " << argv[0] << " <input> <output>\n";
    return -1;
  }

  // Set current file name from input path
  currentFileName = argv[1];

  // Parse #line markers from the input file
  parseLineMarkers(argv[1]);

  std::ifstream inFile(argv[1]);
  if (!inFile) {
    std::cout << "Error: unable to open input file: " << argv[1] << '\n';
    return -2;
  }

  std::ofstream outFile(argv[2]);
  if (!outFile) {
    std::cout << "Error: unable to open output file: " << argv[2] << '\n';
    return -3;
  }

  std::cout << "程序 '" << argv[0] << std::endl;
  std::cout << "输入 '" << argv[1] << std::endl;
  std::cout << "输出 '" << argv[2] << std::endl;

  antlr4::ANTLRInputStream input(inFile);
  SYsULexer lexer(&input);

  antlr4::CommonTokenStream tokens(&lexer);
  tokens.fill();

  for (auto&& token : tokens.getTokens()) {
    print_token(token, tokens, outFile, lexer);
  }
}

