#include "EmitIR.hpp"
#include <llvm/Transforms/Utils/ModuleUtils.h>

#define self (*this)

using namespace asg;

EmitIR::EmitIR(Obj::Mgr& mgr, llvm::LLVMContext& ctx, llvm::StringRef mid)
  : mMgr(mgr)
  , mMod(mid, ctx)
  , mCtx(ctx)
  , mIntTy(llvm::Type::getInt32Ty(ctx))
  , mCurIrb(std::make_unique<llvm::IRBuilder<>>(ctx))
  , mCtorTy(llvm::FunctionType::get(llvm::Type::getVoidTy(ctx), false))
{
}

llvm::Module&
EmitIR::operator()(asg::TranslationUnit* tu)
{
  for (auto&& i : tu->decls)
    self(i);
  return mMod;
}

//==============================================================================
// 类型
//==============================================================================

llvm::Type*
EmitIR::operator()(const Type* type)
{
  if (type->texp == nullptr) {
    switch (type->spec) {
      case Type::Spec::kInt:
        return llvm::Type::getInt32Ty(mCtx);
      // TODO: 在此添加对更多基础类型的处理
      default:
        ABORT();
    }
  }

  Type subt;
  subt.spec = type->spec;
  subt.qual = type->qual;
  subt.texp = type->texp->sub;

  // TODO: 在此添加对指针类型、数组类型和函数类型的处理

  if (auto p = type->texp->dcst<FunctionType>()) {
    std::vector<llvm::Type*> pty;
    // TODO: 在此添加对函数参数类型的处理
    return llvm::FunctionType::get(self(&subt), std::move(pty), false);
  }

  ABORT();
}

//==============================================================================
// 表达式
//==============================================================================

llvm::Value*
EmitIR::operator()(Expr* obj)
{
  // TODO: 在此添加对更多表达式处理的跳转
  if (auto p = obj->dcst<IntegerLiteral>())
    return self(p);
  ABORT();
}

llvm::Constant*
EmitIR::operator()(IntegerLiteral* obj)
{
  return llvm::ConstantInt::get(self(obj->type), obj->val);
}

llvm::Value*
EmitIR::operator()(BinaryExpr* obj)
{
  auto& irb = *mCurIrb;
  auto* lhs = self(obj->lft);
  auto* rhs = self(obj->rht);

  switch (obj->op) {
    case BinaryExpr::kAdd:
      return irb.CreateAdd(lhs, rhs);
    case BinaryExpr::kSub:
      return irb.CreateSub(lhs, rhs);
    case BinaryExpr::kMul:
      return irb.CreateMul(lhs, rhs);
    case BinaryExpr::kDiv:
      return irb.CreateSDiv(lhs, rhs);
    case BinaryExpr::kMod:
      return irb.CreateSRem(lhs, rhs);
    case BinaryExpr::kLt:
      return irb.CreateICmpSLT(lhs, rhs);
    case BinaryExpr::kGt:
      return irb.CreateICmpSGT(lhs, rhs);
    case BinaryExpr::kLe:
      return irb.CreateICmpSLE(lhs, rhs);
    case BinaryExpr::kGe:
      return irb.CreateICmpSGE(lhs, rhs);
    case BinaryExpr::kEq:
      return irb.CreateICmpEQ(lhs, rhs);
    case BinaryExpr::kNe:
      return irb.CreateICmpNE(lhs, rhs);
    case BinaryExpr::kAnd:
      return irb.CreateAnd(lhs, rhs);
    case BinaryExpr::kOr:
      return irb.CreateOr(lhs, rhs);
    case BinaryExpr::kAssign:
      return irb.CreateStore(rhs, lhs);
    case BinaryExpr::kIndex: {
      auto* ptr = irb.CreateGEP(mIntTy, lhs, rhs);
      return irb.CreateLoad(mIntTy, ptr);
    }
    default:
      ABORT();
  }
}

llvm::Value*
EmitIR::operator()(UnaryExpr* obj)
{
  auto& irb = *mCurIrb;
  auto* sub = self(obj->sub);

  switch (obj->op) {
    case UnaryExpr::kPos:
      return sub;
    case UnaryExpr::kNeg:
      return irb.CreateNeg(sub);
    case UnaryExpr::kNot:
      return irb.CreateNot(sub);
    default:
      ABORT();
  }
}

llvm::Value*
EmitIR::operator()(DeclRefExpr* obj)
{
  if (auto* varDecl = obj->decl->dcst<VarDecl>()) {
    return static_cast<llvm::Value*>(varDecl->any);
  }
  if (auto* funcDecl = obj->decl->dcst<FunctionDecl>()) {
    return static_cast<llvm::Value*>(funcDecl->any);
  }
  ABORT();
}

llvm::Value*
EmitIR::operator()(CallExpr* obj)
{
  auto& irb = *mCurIrb;
  auto* callee = self(obj->head);

  std::vector<llvm::Value*> args;
  for (auto* arg : obj->args) {
    args.push_back(self(arg));
  }

  return irb.CreateCall(
    llvm::cast<llvm::FunctionType>(mMod.getFunction(callee->getName())->getFunctionType()),
    callee, args);
}

llvm::Value*
EmitIR::operator()(ImplicitCastExpr* obj)
{
  return self(obj->sub);
}

// TODO: 在此添加对更多表达式类型的处理

//==============================================================================
// 语句
//==============================================================================

void
EmitIR::operator()(Stmt* obj)
{
  // TODO: 在此添加对更多Stmt类型的处理的跳转

  if (auto p = obj->dcst<CompoundStmt>())
    return self(p);

  if (auto p = obj->dcst<ReturnStmt>())
    return self(p);

  if (auto p = obj->dcst<IfStmt>())
    return self(p);

  if (auto p = obj->dcst<WhileStmt>())
    return self(p);

  if (auto p = obj->dcst<DeclStmt>())
    return self(p);

  if (auto p = obj->dcst<ExprStmt>())
    return self(p);

  ABORT();
}

// TODO: 在此添加对更多Stmt类型的处理

void
EmitIR::operator()(CompoundStmt* obj)
{
  // TODO: 可以在此添加对符号重名的处理
  for (auto&& stmt : obj->subs)
    self(stmt);
}

void
EmitIR::operator()(ReturnStmt* obj)
{
  auto& irb = *mCurIrb;

  llvm::Value* retVal;
  if (!obj->expr)
    retVal = nullptr;
  else
    retVal = self(obj->expr);

  mCurIrb->CreateRet(retVal);

  auto exitBb = llvm::BasicBlock::Create(mCtx, "return_exit", mCurFunc);
  mCurIrb->SetInsertPoint(exitBb);
}

void
EmitIR::operator()(IfStmt* obj)
{
  auto& irb = *mCurIrb;
  auto* cond = self(obj->cond);

  auto* thenBb = llvm::BasicBlock::Create(mCtx, "if_then", mCurFunc);
  auto* elseBb = llvm::BasicBlock::Create(mCtx, "if_else", mCurFunc);
  auto* mergeBb = llvm::BasicBlock::Create(mCtx, "if_end", mCurFunc);

  irb.CreateCondBr(cond, thenBb, elseBb);

  irb.SetInsertPoint(thenBb);
  self(obj->then);
  irb.CreateBr(mergeBb);

  irb.SetInsertPoint(elseBb);
  if (obj->else_) {
    self(obj->else_);
  }
  irb.CreateBr(mergeBb);

  irb.SetInsertPoint(mergeBb);
}

void
EmitIR::operator()(WhileStmt* obj)
{
  auto& irb = *mCurIrb;

  auto* condBb = llvm::BasicBlock::Create(mCtx, "while_cond", mCurFunc);
  auto* bodyBb = llvm::BasicBlock::Create(mCtx, "while_body", mCurFunc);
  auto* endBb = llvm::BasicBlock::Create(mCtx, "while_end", mCurFunc);

  irb.CreateBr(condBb);

  irb.SetInsertPoint(condBb);
  auto* cond = self(obj->cond);
  irb.CreateCondBr(cond, bodyBb, endBb);

  irb.SetInsertPoint(bodyBb);
  self(obj->body);
  irb.CreateBr(condBb);

  irb.SetInsertPoint(endBb);
}

void
EmitIR::operator()(DeclStmt* obj)
{
  for (auto* decl : obj->decls) {
    self(decl);
  }
}

void
EmitIR::operator()(ExprStmt* obj)
{
  if (obj->expr) {
    self(obj->expr);
  }
}

//==============================================================================
// 声明
//==============================================================================

void
EmitIR::operator()(Decl* obj)
{
  // TODO: 添加变量声明处理的跳转

  if (auto p = obj->dcst<FunctionDecl>())
    return self(p);

  if (auto p = obj->dcst<VarDecl>())
    return self(p);

  ABORT();
}

// TODO: 添加变量声明的处理

void
EmitIR::operator()(FunctionDecl* obj)
{
  // 创建函数
  auto fty = llvm::dyn_cast<llvm::FunctionType>(self(obj->type));
  auto func = llvm::Function::Create(
    fty, llvm::GlobalVariable::ExternalLinkage, obj->name, mMod);

  obj->any = func;

  if (obj->body == nullptr)
    return;
  auto entryBb = llvm::BasicBlock::Create(mCtx, "entry", func);
  mCurIrb->SetInsertPoint(entryBb);
  auto& entryIrb = *mCurIrb;

  unsigned i = 0;
  for (auto& arg : func->args()) {
    if (i < obj->params.size()) {
      auto* paramDecl = obj->params[i]->dcst<VarDecl>();
      if (paramDecl) {
        auto* alloca = entryIrb.CreateAlloca(self(paramDecl->type), nullptr, paramDecl->name);
        paramDecl->any = alloca;
        entryIrb.CreateStore(&arg, alloca);
      }
      i++;
    }
  }

  // TODO: 添加对函数参数的处理

  // 翻译函数体
  mCurFunc = func;
  self(obj->body);
  auto& exitIrb = *mCurIrb;

  if (fty->getReturnType()->isVoidTy())
    exitIrb.CreateRetVoid();
  else
    exitIrb.CreateUnreachable();
}

void
EmitIR::operator()(VarDecl* obj)
{
  auto& irb = *mCurIrb;
  auto* alloca = irb.CreateAlloca(self(obj->type), nullptr, obj->name);
  obj->any = alloca;

  if (obj->init) {
    auto* initVal = self(obj->init);
    irb.CreateStore(initVal, alloca);
  }
}

