#include "EmitIR.hpp"
#include <llvm/Transforms/Utils/ModuleUtils.h>

#define self (*this)

using namespace asg;

EmitIR::EmitIR(Obj::Mgr& mgr, llvm::LLVMContext& ctx, llvm::StringRef mid)
  : mMgr(mgr)
  , mMod(mid, ctx)
  , mCtx(ctx)
  , mIntTy(llvm::Type::getInt32Ty(ctx))
  , mCurIrb(std::make_unique<llvm::IRBuilder<>>(ctx))
  , mCtorTy(llvm::FunctionType::get(llvm::Type::getVoidTy(ctx), false))
{
}

llvm::Module&
EmitIR::operator()(asg::TranslationUnit* tu)
{
  for (auto&& i : tu->decls)
    self(i);
  return mMod;
}

//==============================================================================
// 类型
//==============================================================================

llvm::Type*
EmitIR::operator()(const Type* type)
{
  if (type->texp == nullptr) {
    switch (type->spec) {
      case Type::Spec::kInt:
        return llvm::Type::getInt32Ty(mCtx);
      // TODO: 在此添加对更多基础类型的处理
      default:
        ABORT();
    }
  }

  Type subt;
  subt.spec = type->spec;
  subt.qual = type->qual;
  subt.texp = type->texp->sub;

  // TODO: 在此添加对指针类型、数组类型和函数类型的处理

  if (auto p = type->texp->dcst<FunctionType>()) {
    std::vector<llvm::Type*> pty;
    // TODO: 在此添加对函数参数类型的处理
    return llvm::FunctionType::get(self(&subt), std::move(pty), false);
  }

  ABORT();
}

//==============================================================================
// 表达式
//==============================================================================

llvm::Value*
EmitIR::operator()(Expr* obj)
{
  // TODO: 在此添加对更多表达式处理的跳转
  if (auto p = obj->dcst<IntegerLiteral>())
    return self(p);
  ABORT();
}

llvm::Constant*
EmitIR::operator()(IntegerLiteral* obj)
{
  return llvm::ConstantInt::get(self(obj->type), obj->val);
}

llvm::Value*
EmitIR::operator()(BinaryExpr* obj)
{
  auto& irb = *mCurIrb;
  auto* lhs = self(obj->lft);
  auto* rhs = self(obj->rht);

  switch (obj->op) {
    case BinaryExpr::kAdd:
      return irb.CreateAdd(lhs, rhs);
    case BinaryExpr::kSub:
      return irb.CreateSub(lhs, rhs);
    case BinaryExpr::kMul:
      return irb.CreateMul(lhs, rhs);
    case BinaryExpr::kDiv:
      return irb.CreateSDiv(lhs, rhs);
    case BinaryExpr::kMod:
      return irb.CreateSRem(lhs, rhs);
    case BinaryExpr::kLt:
      return irb.CreateICmpSLT(lhs, rhs);
    case BinaryExpr::kGt:
      return irb.CreateICmpSGT(lhs, rhs);
    case BinaryExpr::kLe:
      return irb.CreateICmpSLE(lhs, rhs);
    case BinaryExpr::kGe:
      return irb.CreateICmpSGE(lhs, rhs);
    case BinaryExpr::kEq:
      return irb.CreateICmpEQ(lhs, rhs);
    case BinaryExpr::kNe:
      return irb.CreateICmpNE(lhs, rhs);
    case BinaryExpr::kAnd:
      return irb.CreateAnd(lhs, rhs);
    case BinaryExpr::kOr:
      return irb.CreateOr(lhs, rhs);
    case BinaryExpr::kAssign:
      return irb.CreateStore(rhs, lhs);
    case BinaryExpr::kIndex: {
      auto* ptr = irb.CreateGEP(mIntTy, lhs, rhs);
      return irb.CreateLoad(mIntTy, ptr);
    }
    default:
      ABORT();
  }
}

llvm::Value*
EmitIR::operator()(UnaryExpr* obj)
{
  auto& irb = *mCurIrb;
  auto* sub = self(obj->sub);

  switch (obj->op) {
    case UnaryExpr::kPos:
      return sub;
    case UnaryExpr::kNeg:
      return irb.CreateNeg(sub);
    case UnaryExpr::kNot:
      return irb.CreateNot(sub);
    default:
      ABORT();
  }
}

llvm::Value*
EmitIR::operator()(DeclRefExpr* obj)
{
  auto& irb = *mCurIrb;
  if (auto* varDecl = obj->decl->dcst<VarDecl>()) {
    auto* alloca = static_cast<llvm::Value*>(varDecl->any);
    return irb.CreateLoad(mIntTy, alloca);
  }
  if (auto* funcDecl = obj->decl->dcst<FunctionDecl>()) {
    return static_cast<llvm::Value*>(funcDecl->any);
  }
  ABORT();
}

llvm::Value*
EmitIR::operator()(CallExpr* obj)
{
  auto& irb = *mCurIrb;
  auto* callee = self(obj->head);

  std::vector<llvm::Value*> args;
  for (auto* arg : obj->args) {
    args.push_back(self(arg));
  }

  return irb.CreateCall(
    llvm::cast<llvm::FunctionType>(mMod.getFunction(callee->getName())->getFunctionType()),
    callee, args);
}

llvm::Value*
EmitIR::operator()(ImplicitCastExpr* obj)
{
  return self(obj->sub);
}

