  auto* elseBb = llvm::BasicBlock::Create(mCtx, "if_else", mCurFunc);
  auto* mergeBb = llvm::BasicBlock::Create(mCtx, "if_end", mCurFunc);

  irb.CreateCondBr(cond, thenBb, elseBb);

  irb.SetInsertPoint(thenBb);
  self(obj->then);
  irb.CreateBr(mergeBb);

  irb.SetInsertPoint(elseBb);
  if (obj->else_) {
