void
EmitIR::operator()(Decl* obj)
{
  // TODO: 添加变量声明处理的跳转

  if (auto p = obj->dcst<FunctionDecl>())
    return self(p);

  if (auto p = obj->dcst<VarDecl>())
    return self(p);

  ABORT();
}

// TODO: 添加变量声明的处理

void
EmitIR::operator()(FunctionDecl* obj)
{
  // 创建函数
  auto fty = llvm::dyn_cast<llvm::FunctionType>(self(obj->type));
  auto func = llvm::Function::Create(
    fty, llvm::GlobalVariable::ExternalLinkage, obj->name, mMod);

  obj->any = func;

  if (obj->body == nullptr)
    return;
  auto entryBb = llvm::BasicBlock::Create(mCtx, "entry", func);
  mCurIrb->SetInsertPoint(entryBb);
  auto& entryIrb = *mCurIrb;

  unsigned i = 0;
  for (auto& arg : func->args()) {
    if (i < obj->params.size()) {
      auto* paramDecl = obj->params[i]->dcst<VarDecl>();
      if (paramDecl) {
        auto* alloca = entryIrb.CreateAlloca(self(paramDecl->type), nullptr, paramDecl->name);
        paramDecl->any = alloca;
        entryIrb.CreateStore(&arg, alloca);
      }
      i++;
    }
  }

  // TODO: 添加对函数参数的处理

  // 翻译函数体
  mCurFunc = func;
  self(obj->body);
  auto& exitIrb = *mCurIrb;

  if (fty->getReturnType()->isVoidTy())
    exitIrb.CreateRetVoid();
  else
    exitIrb.CreateUnreachable();
}

void
EmitIR::operator()(VarDecl* obj)
{
  auto& irb = *mCurIrb;
  auto* alloca = irb.CreateAlloca(self(obj->type), nullptr, obj->name);
  obj->any = alloca;

  if (obj->init) {
    auto* initVal = self(obj->init);
    irb.CreateStore(initVal, alloca);
  }
}

